import { ChevronLeft, User, LogOut, Save, Database, Globe, Disc } from 'lucide-react';

// Composant Scie Circulaire SVG
const CircularSawIcon = ({ className }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <circle cx="12" cy="12" r="10" />
    <circle cx="12" cy="12" r="3" />
    <path d="M12 2v4" /><path d="M12 18v4" />
    <path d="M4.93 4.93l2.83 2.83" /><path d="M16.24 16.24l2.83 2.83" />
    <path d="M2 12h4" /><path d="M18 12h4" />
    <path d="M4.93 19.07l2.83-2.83" /><path d="M16.24 7.76l2.83-2.83" />
  </svg>
);

export default function Header({ 
  title, subtitle, onBack, user, onLogout, steps, 
  onSave, saving, saveMsg, lang, onToggleLang 
}) {
  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-[#0a0a0a]/95 backdrop-blur-md border-b border-white/5 shadow-xl h-16">
      <div className="max-w-5xl mx-auto px-4 h-full flex items-center justify-between">

        {/* GAUCHE */}
        <div className="flex items-center gap-3 flex-1 min-w-0">
          {onBack && (
            <button onClick={onBack} className="p-2 -ml-2 text-slate-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
              <ChevronLeft className="w-6 h-6" />
            </button>
          )}
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => !onBack && window.location.reload()}>
            <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-600 rounded-lg flex items-center justify-center shadow-lg shadow-orange-500/20 hover:rotate-45 transition-transform duration-500">
              <CircularSawIcon className="w-5 h-5 text-white" />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-base font-bold text-white leading-tight">PanelCut <span className="text-orange-500">Pro</span></h1>
              {subtitle && <p className="text-[10px] text-slate-400 uppercase tracking-wide">{subtitle}</p>}
            </div>
          </div>
        </div>

        {/* CENTRE (Stepper) */}
        {steps && steps.length > 0 && (
          <div className="absolute left-1/2 -translate-x-1/2 hidden md:flex items-center bg-[#111] border border-white/5 rounded-full px-2 py-1">
            {steps.map((step, i) => (
              <div key={i} className="flex items-center">
                <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${step.active ? 'bg-orange-500 text-white shadow-lg shadow-orange-500/30' : 'text-slate-500'}`}>
                  <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${step.active ? 'bg-white/20' : 'bg-white/5 border border-white/10'}`}>{i+1}</span>
                  <span className="hidden lg:inline">{step.label}</span>
                </div>
                {i < steps.length - 1 && <div className={`w-6 h-0.5 mx-1 ${step.active ? 'bg-orange-500/50' : 'bg-white/5'}`} />}
              </div>
            ))}
          </div>
        )}

        {/* DROITE (Actions) */}
        <div className="flex items-center gap-2 flex-1 justify-end">

          {/* Bouton Sauvegarder (Disquette) */}
          {onSave && (
            <button 
              onClick={onSave} 
              disabled={saving}
              className="group relative flex items-center justify-center w-9 h-9 bg-white/5 hover:bg-green-600 text-slate-300 hover:text-white rounded-lg border border-white/10 hover:border-green-500 transition-all disabled:opacity-50"
              title="Sauvegarder"
            >
              {saving ? <Database className="w-4 h-4 animate-spin" /> : <Disc className="w-4 h-4 group-hover:scale-110 transition-transform" />}
              {!saving && <span className="absolute -bottom-8 bg-black text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">Sauvegarder</span>}
            </button>
          )}

          {/* Bouton Langue (Globe) */}
          {onToggleLang && (
            <button 
              onClick={onToggleLang} 
              className="group relative flex items-center justify-center w-9 h-9 bg-white/5 hover:bg-blue-600 text-slate-300 hover:text-white rounded-lg border border-white/10 hover:border-blue-500 transition-all"
              title="Changer de langue"
            >
              <Globe className="w-4 h-4 group-hover:rotate-12 transition-transform" />
              <span className="absolute text-[9px] font-bold ml-3.5 mt-2.5 pointer-events-none">{lang === 'fr' ? 'EN' : 'FR'}</span>
            </button>
          )}

          {/* Séparateur */}
          {(onSave || onToggleLang || user) && <div className="w-px h-4 bg-white/10 mx-1" />}

          {/* Profil */}
          {user ? (
            <div className="flex items-center gap-2 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full pl-1 pr-2 py-1 cursor-pointer transition-colors" onClick={onLogout}>
              <div className="w-6 h-6 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-[10px] font-bold text-white">
                {user.email[0].toUpperCase()}
              </div>
              <span className="text-xs text-slate-300 hidden sm:block mr-1 max-w-[80px] truncate">{user.email.split('@')[0]}</span>
              <LogOut className="w-3.5 h-3.5 text-slate-500 hover:text-red-400" />
            </div>
          ) : (
            <div className="w-8 h-8 bg-white/5 rounded-full flex items-center justify-center border border-white/5">
              <User className="w-4 h-4 text-slate-500" />
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
